function solve(n: number, edges: number[][], label: string): number {
    const graph: number[][] = new Array(n).fill(0).map(() => new Array<number>());

    // Build the graph
    for (const [u, v] of edges) {
        graph[u].push(v);
        graph[v].push(u);
    }

    // Use bitmask to represent visited nodes
    const dp: Map<number, Map<number, number>> = new Map();

    // Helper function to perform DFS and find the longest palindrome
    function dfs(node: number, visited: number, path: string[]): [number, string] {
        // Check if this state has been computed before
        const key = visited << 2 | node;
        if (dp.has(key)) {
            return [dp.get(key)!.get(node) || 0, ""]; // Return cached result
        }

        // Initialize the maximum length and the palindrome string
        let maxLength = 1;
        let maxPalindrome = label[node];

        // Try to move to each neighbor
        for (const neighbor of graph[node]) {
            if ((visited & (1 << neighbor)) === 0) {
                // Mark the neighbor as visited
                const newVisited = visited | (1 << neighbor);

                // Recursively visit the neighbor
                const [nextLength, nextPalindrome] = dfs(neighbor, newVisited, path);

                // Check if the current path can form a palindrome with the next path
                const combined = label[node] + nextPalindrome;
                const reversedCombined = combined.split('').reverse().join('');

                // If the combined string is a palindrome, update the maximum length and palindrome
                if (combined === reversedCombined) {
                    if (nextLength + 1 > maxLength) {
                        maxLength = nextLength + 1;
                        maxPalindrome = combined;
                    }
                }
            }
        }

        // Cache the result for this state
        if (!dp.has(key)) {
            dp.set(key, new Map());
        }
        dp.get(key)!.set(node, maxLength);

        return [maxLength, maxPalindrome];
    }

    // Start DFS from each node
    let maxLength = 0;
    let maxPalindrome = "";

    for (let i = 0; i < n; i++) {
        const [length, palindrome] = dfs(i, 1 << i, [label[i]]);
        if (length > maxLength) {
            maxLength = length;
            maxPalindrome = palindrome;
        }
    }

    return maxLength;
}

