public static long solve(long n, long[][] edges, String label) {
    int size = (int) n;
    List<List<Integer>> graph = new ArrayList<>(size);
    for (int i = 0; i < size; i++) {
        graph.add(new ArrayList<>());
    }

    for (int i = 0; i < edges.length; i++) {
        int u = (int) edges[i][0];
        int v = (int) edges[i][1];
        graph.get(u).add(v);
        graph.get(v).add(u);
    }

    Map<Long, Map<Integer, Integer>> dp = new HashMap<>();

    // Helper function to perform DFS and find the longest palindrome
    function dfs(int node, int visited, List<Character> path) {
        long key = (visited << 2) | node;
        if (dp.containsKey(key)) {
            return dp.get(key).get(node);
        }

        int maxLength = 1;
        char[] currentChar = new char[1];
        currentChar[0] = label.charAt(node);

        for (int neighbor : graph.get(node)) {
            if ((visited & (1 << neighbor)) == 0) {
                int newVisited = visited | (1 << neighbor);
                int nextLength = dfs(neighbor, newVisited, path);

                String combined = label.charAt(node) + new String(path);
                String reversedCombined = new StringBuilder(combined).reverse().toString();

                if (combined.equals(reversedCombined)) {
                    if (nextLength + 1 > maxLength) {
                        maxLength = nextLength + 1;
                        currentChar = combined.toCharArray();
                    }
                }
            }
        }

        if (!dp.containsKey(key)) {
            dp.put(key, new HashMap<>());
        }
        dp.get(key).put(node, maxLength);

        return maxLength;
    }

    int maxLength = 0;
    for (int i = 0; i < size; i++) {
        int length = dfs(i, 1 << i, new ArrayList<>(Arrays.asList(label.charAt(i))));
        if (length > maxLength) {
            maxLength = length;
        }
    }

    return maxLength;
}
